#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e4+5;int n,num[MAXN],tmp[MAXN],ans[MAXN];
int main(void){
    scanf("%d",&n);
    for(int i=1;i<=n;++i)scanf("%d",num+i),tmp[i]=1;
    for(int i=1;i<=n;++i){
        for(int j=1;j<i;++j)
            if(num[i]>=num[j]&&tmp[i]<tmp[j]+1)tmp[i]=tmp[j]+1,ans[i]=ans[j];
        ans[i]+=num[i];
    }for(int i=1;i<=n;++i)printf("%d ",ans[i]);
    return false;
}
